//纤维轴温度读取发送
void ui_event_ApplyButton1(lv_event_t * e)
{
    lv_event_code_t event_code = lv_event_get_code(e);

    if(event_code == LV_EVENT_CLICKED) {

        const char * input_text = lv_textarea_get_text(ui_T1Enter1);//从文本框读字符串

        if (input_text != NULL && strlen(input_text) > 0) {
            
            float target_temp = (float)atof(input_text);//字符串转浮点

            PID_send_command(1, target_temp, true);

            printf("设置纤维加热温度为: %.1f\n", target_temp);
        }
        else 
        {
            printf("输入为空，未发送指令\n");
        }
    }
}

