void ui_event_V1Enter(lv_event_t * e)//纤维挤出速度
{
    lv_event_code_t event_code = lv_event_get_code(e);

    if(event_code == LV_EVENT_CLICKED) {
        _ui_keyboard_set_target(ui_Keyboard1,  ui_V1Enter);
    }
}

//纤维挤出速度读取发送
void ui_event_ApplyButton3(lv_event_t * e)
{
    lv_event_code_t event_code = lv_event_get_code(e);

    if(event_code == LV_EVENT_CLICKED) {

        const char * input_text = lv_textarea_get_text(ui_V1Enter);//从文本框读字符串

        if (input_text != NULL && strlen(input_text) > 0) {
            
            float target_speed = (float)atof(input_text);//字符串转浮点

            motor3_set_speed_mm_per_s(target_speed);

            printf("设置纤维挤出速度为: %.1f\n", target_speed);
        }
        else 
        {
            printf("输入为空，未发送指令\n");
        }
    }
}

